package com.example.ecommerce.order;

import com.example.ecommerce.order.types.Order;
import com.example.ecommerce.order.types.OrderItem;
import com.example.ecommerce.order.types.OrderResponse;
import javax.jws.WebService;
import java.util.UUID;
import java.util.logging.Logger;

@WebService(endpointInterface = "com.example.ecommerce.order.OrderProcessingService",
            name = "OrderProcessingServiceImpl",
            serviceName = "OrderProcessingService",
            targetNamespace = "http://order.ecommerce.example.com/")
public class OrderProcessingServiceImpl implements OrderProcessingService {

    private static final Logger LOGGER = Logger.getLogger(OrderProcessingServiceImpl.class.getName());

    @Override
    public OrderResponse processOrder(Order order) {
        OrderResponse response = new OrderResponse();
        double totalPrice = 0.0;

        if (order == null || order.getOrderItems() == null || order.getOrderItems().isEmpty()) {
            response.setOrderId("N/A");
            response.setTotalPrice(0.0);
            response.setStatus("FAILED");
            response.setMessage("Order or order items cannot be empty.");
            LOGGER.warning("Order processing failed: Order or order items were empty for customer " + (order != null ? order.getCustomerId() : "N/A"));
            return response;
        }

        try {
            for (OrderItem item : order.getOrderItems()) {
                if (item.getPrice() < 0 || item.getQuantity() <= 0) {
                    throw new IllegalArgumentException("Invalid price or quantity for item: " + item.getItemId());
                }
                totalPrice += item.getPrice() * item.getQuantity();
            }

            // Simulate order processing logic
            String orderId = UUID.randomUUID().toString();
            LOGGER.info("Order " + orderId + " received for customer " + order.getCustomerId() + " with total price: " + totalPrice);

            response.setOrderId(orderId);
            response.setTotalPrice(totalPrice);
            response.setStatus("PROCESSED");
            response.setMessage("Order successfully processed.");

        } catch (IllegalArgumentException e) {
            response.setOrderId("N/A");
            response.setTotalPrice(0.0);
            response.setStatus("FAILED");
            response.setMessage("Validation error: " + e.getMessage());
            LOGGER.severe("Order processing failed due to validation error: " + e.getMessage());
        } catch (Exception e) {
            response.setOrderId("N/A");
            response.setTotalPrice(0.0);
            response.setStatus("FAILED");
            response.setMessage("An unexpected error occurred: " + e.getMessage());
            LOGGER.severe("Order processing failed due to unexpected error: " + e.getMessage());
        }

        return response;
    }
}

